func lengthOfLongestSubstring(s string) int {
	maxLen := 0

	type set map[byte]int // char->index
	var diffSet set
	clearSet := func() {
		diffSet = make(set)
	}

	clearSet()
	for i := 0; i < len(s); {
		char := s[i]
		//sc := string(char)
		//print(sc, " ")
		if idx, ok := diffSet[char]; !ok {
			diffSet[char] = i
			i++
			if len(diffSet) > maxLen {
				maxLen = len(diffSet)
			}
		} else {
			i = idx + 1
			clearSet()
		}
	}

	return maxLen
}

